languages.java:
import java.util.*;
class Main{
 public static void main(String[] args){
  Scanner sc = new Scanner(System.in);
  String s = sc.next();
  Stack<Character> stack = new Stack<>();
  for(char ch : s.toCharArray()){
   if(ch == '(')
    stack.push(ch);
   else
    stack.pop();
  }
  if(stack.empty())
   System.out.println("Valid");
 }
}

