class Main{
 public static void main(String[] args){
  Scanner sc = new Scanner(System.in);
  int n = sc.nextInt();
  int min = 0;
  int profit;
  for(int i=0;i<n;i++){
   int price = sc.nextInt();
   if(price < min)
    min = price;
   profit = Math.max(profit, price - min);
  }
  System.out.println(profit);
 }
}

